 83→  const upToCaret = text.slice(0, safeCaret);
 84→  const triggerIndex = upToCaret.lastIndexOf("@");
 85→  if (triggerIndex === -1) {
 86→    return null;
 87→  }
 88→
 89→  if (triggerIndex > 0) {
 90→    const previousChar = upToCaret[triggerIndex - 1];
 91→    if (previousChar && !MENTION_TRIGGER_PREFIX.test(previousChar)) {
 92→      return null;
 93→    }
 94→  }
 95→
 96→  const query = upToCaret.slice(triggerIndex + 1);
 97→  if (STOP_CHARS.test(query)) {
 98→    return null;
 99→  }
100→
101→  return {
102→    start: triggerIndex,
103→    end: safeCaret,
104→    query,
105→  };
106→};
