    flatOptions,
    sections,
    activeIndex,
    setActiveIndex,
    handleTextChange,
    handleCaretChange,
    handleKeyDown,
    selectOption,
    closeMenu,
    workspaceStatus,
    workspaceError,
    retryWorkspace,
    workspaceFileCount: workspaceFiles.length,
  };
};

