  const handleTextChange = useCallback(
    (value: string, caret: number | null) => {
      setRange(detectMention(value, caret));
    },
    [],
  );

  const handleCaretChange = useCallback(
    (caret: number | null) => {
      setRange(detectMention(text, caret));
