49→  const now = new Date();
50→  const diff = now.getTime() - date.getTime();
51→  const minutes = Math.floor(diff / 60000);
52→
53→  if (minutes < 1) {
54→    return "Just now";
55→  } else if (minutes < 60) {
56→    return `${minutes}m ago`;
