 513→  const parseUserInput = useCallback(
 514→    (input: string | ContentPart[]): ParsedUserInput => {
 515→      if (typeof input === "string") {
 516→        return { text: input, attachments: [] };
 517→      }
 518→
 519→      const textParts: string[] = [];
 520→      const attachments: MessageAttachmentPart[] = [];
 521→      const uploadedFilePaths: string[] = [];
 522→      let inUploadedFilesBlock = false;
 523→      const collectUploadedFilePath = (line: string): boolean => {
 524→        const match = NUMBERED_LIST_ITEM_REGEX.exec(line.trim());
 525→        if (!match) {
 526→          return false;
 527→        }
 528→        const filePath = match[1].trim();
 529→        if (
 530→          !(
 531→            filePath &&
 532→            (filePath.startsWith("/") || filePath.startsWith("uploads/"))
 533→          )
 534→        ) {
 535→          return false;
 536→        }
 537→        uploadedFilePaths.push(filePath);
 538→        return true;
 539→      };
 540→
 541→      // Pending metadata for associating with next image_url part
 542→      let pendingFilename: string | undefined;
 543→      let pendingMediaType: string | undefined;
 544→
 545→      // State for collecting document content
 546→      let inDocument = false;
 547→      let documentFilename: string | undefined;
 548→      let documentMediaType: string | undefined;
 549→      let documentContent: string[] = [];
 550→
 551→      for (const part of input) {
 552→        if (part.type === "text" || part.type === "input_text") {
 553→          const text = part.text;
 554→
 555→          // New format: <image path="/path/to/uploads/file.name" content_type="image/png">
 556→          const imageTagMatch = IMAGE_TAG_REGEX.exec(text);
 557→          if (imageTagMatch) {
 558→            // Extract filename from path
 559→            const fullPath = imageTagMatch[1];
 560→            pendingFilename = fullPath.split("/").pop() ?? fullPath;
 561→            pendingMediaType = imageTagMatch[2];
 562→            continue; // Skip this text part, it's just metadata
 563→          }
 564→
 565→          // New format: </image> closing tag - skip it
 566→          if (text.trim() === "</image>") {
 567→            continue;
 568→          }
 569→
 570→          // New format: <video path="/path/to/uploads/file.name" content_type="video/mp4">
 571→          const videoTagMatch = VIDEO_TAG_REGEX.exec(text);
 572→          if (videoTagMatch) {
 573→            // Extract filename from path
 574→            const fullPath = videoTagMatch[1];
 575→            pendingFilename = fullPath.split("/").pop() ?? fullPath;
 576→            pendingMediaType = videoTagMatch[2];
 577→            continue; // Skip this text part, it's just metadata
 578→          }
 579→
 580→          // New format: </video> closing tag - create attachment if no video_url follows
 581→          if (text.trim() === "</video>") {
 582→            // If we have pending video metadata but no video_url part will follow,
 583→            // create a video attachment from the session uploads.
 584→            if (pendingFilename && pendingMediaType?.startsWith("video/")) {
 585→              const url = getSessionUploadUrl(pendingFilename);
 586→              if (url) {
 587→                attachments.push({
 588→                  type: "file",
 589→                  mediaType: pendingMediaType,
 590→                  filename: pendingFilename,
 591→                  url,
 592→                });
 593→              } else {
 594→                attachments.push({
 595→                  kind: "video-nopreview",
 596→                  mediaType: pendingMediaType,
 597→                  filename: pendingFilename,
 598→                });
 599→              }
 600→              pendingFilename = undefined;
 601→              pendingMediaType = undefined;
 602→            }
 603→            continue;
 604→          }
 605→
 606→          // New format: <document path="/path/to/uploads/..." content_type="..."> - start collecting
 607→          const documentTagMatch = DOCUMENT_TAG_REGEX.exec(text);
 608→          if (documentTagMatch) {
 609→            inDocument = true;
 610→            // Extract filename from path
 611→            const fullPath = documentTagMatch[1];
 612→            documentFilename = fullPath.split("/").pop() ?? fullPath;
 613→            documentMediaType = documentTagMatch[2];
 614→            documentContent = [];
 615→            continue;
 616→          }
 617→
 618→          // New format: </document> - finalize document attachment
 619→          if (text.trim() === "</document>") {
 620→            if (inDocument && documentFilename) {
 621→              const content = documentContent.join("");
 622→              const bytes = new TextEncoder().encode(content);
 623→              const base64 = btoa(String.fromCharCode(...bytes));
 624→              const dataUrl = `data:${documentMediaType ?? "text/plain"};base64,${base64}`;
 625→              attachments.push({
 626→                type: "file",
 627→                mediaType: documentMediaType ?? "text/plain",
 628→                filename: documentFilename,
 629→                url: dataUrl,
 630→              });
 631→            }
 632→            inDocument = false;
 633→            documentFilename = undefined;
 634→            documentMediaType = undefined;
 635→            documentContent = [];
 636→            continue;
 637→          }
 638→
 639→          // If inside document, collect content instead of adding to textParts
 640→          if (inDocument) {
 641→            documentContent.push(text);
 642→            continue;
 643→          }
 644→
 645→          const lines = text.split(NEWLINE_REGEX);
 646→          const filteredLines: string[] = [];
 647→
 648→          for (const line of lines) {
 649→            if (line.includes("<uploaded_files>")) {
 650→              inUploadedFilesBlock = true;
 651→              continue;
 652→            }
 653→            if (line.includes("</uploaded_files>")) {
 654→              inUploadedFilesBlock = false;
 655→              continue;
 656→            }
 657→            if (inUploadedFilesBlock) {
 658→              collectUploadedFilePath(line);
 659→              continue;
 660→            }
 661→            if (collectUploadedFilePath(line)) {
 662→              continue;
 663→            }
 664→            filteredLines.push(line);
 665→          }
 666→
 667→          const filteredText = filteredLines.join("\n");
 668→
 669→          // Legacy format: `uploads/file.name`
 670→          const legacyMatch = LEGACY_UPLOADS_REGEX.exec(filteredText);
 671→          if (legacyMatch) {
 672→            pendingFilename = legacyMatch[1];
 673→          }
 674→
 675→          // Only add non-metadata text parts
 676→          if (filteredText.trim()) {
 677→            textParts.push(filteredText);
 678→          }
 679→          continue;
 680→        }
 681→
 682→        if (part.type === "image_url") {
 683→          const inferredMediaType = parseMediaTypeFromDataUrl(
 684→            part.image_url.url,
 685→          );
 686→          attachments.push({
 687→            type: "file",
 688→            mediaType: pendingMediaType ?? inferredMediaType ?? "image/*",
 689→            filename: pendingFilename,
 690→            url: part.image_url.url,
 691→          });
 692→          pendingFilename = undefined;
 693→          pendingMediaType = undefined;
 694→        }
 695→
 696→        if (part.type === "video_url") {
 697→          const inferredMediaType = parseMediaTypeFromDataUrl(
 698→            part.video_url.url,
 699→          );
 700→          attachments.push({
 701→            type: "file",
 702→            mediaType: pendingMediaType ?? inferredMediaType ?? "video/*",
 703→            filename: pendingFilename,
 704→            url: part.video_url.url,
 705→          });
 706→          pendingFilename = undefined;
 707→          pendingMediaType = undefined;
 708→        }
 709→      }
 710→
 711→      if (uploadedFilePaths.length > 0) {
 712→        const existingFilenames = new Set(
 713→          attachments
 714→            .map((attachment) => attachment.filename)
 715→            .filter((filename): filename is string => Boolean(filename)),
 716→        );
 717→        const seenUploadedFilenames = new Set<string>();
 718→        for (const filePath of uploadedFilePaths) {
 719→          const filename = filePath.split("/").pop() ?? filePath;
 720→          if (!filename) {
 721→            continue;
 722→          }
 723→          if (
 724→            existingFilenames.has(filename) ||
 725→            seenUploadedFilenames.has(filename)
 726→          ) {
 727→            continue;
 728→          }
 729→          attachments.push({
 730→            kind: "nopreview",
 731→            filename,
 732→          });
 733→          seenUploadedFilenames.add(filename);
 734→        }
 735→      }
 736→
 737→      return { text: textParts.join("\n\n").trim(), attachments };
 738→    },
 739→    [getSessionUploadUrl, parseMediaTypeFromDataUrl],
 740→  );
