 817→  // Process a SubagentEvent: accumulate inner events into parent Task tool's subagentSteps
 818→  const processSubagentEvent = useCallback(
 819→    (taskToolCallId: string, innerType: string, innerPayload: unknown) => {
 820→      setMessages((prev) => {
 821→        // Find the parent Task tool message by toolCallId
 822→        const parentIdx = prev.findIndex(
 823→          (msg) => msg.toolCall?.toolCallId === taskToolCallId,
 824→        );
 825→        if (parentIdx === -1) return prev;
 826→
 827→        const parentMsg = prev[parentIdx];
 828→        const steps: SubagentStep[] = [
 829→          ...(parentMsg.toolCall?.subagentSteps ?? []),
 830→        ];
 831→
 832→        switch (innerType) {
 833→          case "ContentPart": {
 834→            const cp = innerPayload as {
 835→              type: string;
 836→              think?: string;
 837→              text?: string;
 838→            };
 839→            if (cp.type === "think" && cp.think) {
 840→              const last = steps[steps.length - 1];
 841→              if (last?.kind === "thinking") {
 842→                steps[steps.length - 1] = {
 843→                  ...last,
 844→                  text: last.text + cp.think,
 845→                };
 846→              } else {
 847→                steps.push({ kind: "thinking", text: cp.think });
 848→              }
 849→            } else if (cp.type === "text" && cp.text) {
 850→              const last = steps[steps.length - 1];
 851→              if (last?.kind === "text") {
 852→                steps[steps.length - 1] = {
 853→                  ...last,
 854→                  text: last.text + cp.text,
 855→                };
 856→              } else {
 857→                steps.push({ kind: "text", text: cp.text });
 858→              }
 859→            }
 860→            break;
 861→          }
 862→
 863→          case "ToolCall": {
 864→            const tc = innerPayload as {
 865→              type: string;
 866→              id: string;
 867→              function: { name: string; arguments: string };
 868→            };
 869→            const initialArgs = tc.function.arguments || "";
 870→            let parsedInput: unknown;
 871→            try {
 872→              parsedInput = JSON.parse(initialArgs || "{}");
 873→            } catch {
 874→              // not valid JSON yet
 875→            }
 876→            steps.push({
 877→              kind: "tool-call",
 878→              toolCallId: tc.id,
 879→              toolName: tc.function.name,
 880→              rawArgs: initialArgs,
 881→              input: parsedInput,
 882→              status: "running",
 883→            });
 884→            break;
 885→          }
 886→
 887→          case "ToolCallPart": {
 888→            const tcp = innerPayload as { arguments_part: string };
 889→            // Find the last running tool-call step and append arguments
 890→            for (let i = steps.length - 1; i >= 0; i--) {
 891→              const step = steps[i];
 892→              if (step.kind === "tool-call" && step.status === "running") {
 893→                const newArgs = (step.rawArgs ?? "") + tcp.arguments_part;
 894→                let parsedInput: unknown;
 895→                try {
 896→                  parsedInput = JSON.parse(newArgs);
 897→                } catch {
 898→                  // not complete JSON yet
 899→                }
 900→                steps[i] = {
 901→                  ...step,
 902→                  rawArgs: newArgs,
 903→                  input: parsedInput ?? step.input,
 904→                };
 905→                break;
 906→              }
 907→            }
 908→            break;
 909→          }
 910→
 911→          case "ToolResult": {
 912→            const tr = innerPayload as {
 913→              tool_call_id: string;
 914→              return_value: {
 915→                is_error: boolean;
 916→                output: Array<{ text?: string }> | string;
 917→                message: string;
 918→              };
 919→            };
 920→            for (let i = steps.length - 1; i >= 0; i--) {
 921→              const step = steps[i];
 922→              if (
 923→                step.kind === "tool-call" &&
 924→                step.toolCallId === tr.tool_call_id
 925→              ) {
 926→                const outputStr = Array.isArray(tr.return_value.output)
 927→                  ? tr.return_value.output
 928→                      .map((p) => p.text ?? "")
 929→                      .filter(Boolean)
 930→                      .join("\n")
 931→                  : tr.return_value.output;
 932→                steps[i] = {
 933→                  ...step,
 934→                  status: tr.return_value.is_error ? "error" : "success",
 935→                  output: outputStr || undefined,
 936→                  errorText: tr.return_value.is_error
 937→                    ? tr.return_value.message || undefined
 938→                    : undefined,
 939→                };
 940→                break;
 941→              }
 942→            }
 943→            break;
 944→          }
 945→
 946→          case "SubagentEvent": {
 947→            // Nested subagent — deep nesting is rare in practice.
 948→            // For now we skip nested SubagentEvents; the parent subagent's
 949→            // direct tool calls/text/thinking are already captured.
 950→            break;
 951→          }
 952→
 953→          default:
 954→            // Ignore StepBegin, TurnBegin, TurnEnd, StatusUpdate, etc.
 955→            break;
 956→        }
 957→
 958→        const next = [...prev];
 959→        next[parentIdx] = {
 960→          ...parentMsg,
 961→          toolCall: {
 962→            ...parentMsg.toolCall!,
 963→            subagentSteps: steps,
 964→            subagentRunning: true,
 965→          },
 966→        };
 967→        return next;
 968→      });
 969→    },
 970→    [setMessages],
 971→  );
