1000→            id: userMessageId,
1001→            role: "user",
1002→            turnIndex: currentTurnIndex,
1003→            content:
1004→              parsedUserInput.text ||
1005→              (parsedUserInput.attachments.length > 0
1006→                ? ""
1007→                : safeStringify(event.payload.user_input ?? "")),
1008→            attachments:
1009→              parsedUserInput.attachments.length > 0
1010→                ? parsedUserInput.attachments
1011→                : undefined,
1012→          };
1013→
1014→          upsertMessage(userMessage);
1015→          break;
1016→        }
1017→
1018→        case "StepBegin": {
1019→          setCurrentStep(event.payload.n);
1020→          resetStepState();
1021→          if (!isReplay) {
1022→            setStatus("streaming");
1023→          }
1024→          break;
1025→        }
1026→
1027→        case "ContentPart": {
1028→          if (!isReplay) {
1029→            clearAwaitingFirstResponse();
1030→          }
1031→          if (event.payload.type === "think" && event.payload.think) {
1032→            // Accumulate thinking content
1033→            currentThinkingRef.current += event.payload.think;
1034→
1035→            // Create or update thinking message
1036→            if (!thinkingMessageIdRef.current) {
1037→              thinkingMessageIdRef.current = getNextMessageId("assistant");
1038→              const thinkingMsg: LiveMessage = {
