  1→import { useCallback, useEffect, useMemo, useRef, useState } from "react";
  2→import type { KeyboardEvent } from "react";
  3→import type { FileUIPart } from "ai";
  4→import type { SessionFileEntry } from "@/hooks/useSessions";
  5→
  6→const STOP_CHARS = /[\s,;:!?,()[\]{}<>"'`]/;
  7→const MENTION_TRIGGER_PREFIX = /\s|[([{]/;
  8→const LEADING_DOT_SLASH = /^\.\//;
  9→const NON_WHITESPACE_START = /^\S/;
 10→const MAX_WORKSPACE_FILES = 500;
 11→const MAX_DIRECTORY_SCANS = 200;
 12→const WORKSPACE_STALE_MS = 30_000;
 13→const DIRECTORY_QUERY_DEBOUNCE_MS = 300;
 14→
 15→type MentionRange = {
 16→  start: number;
 17→  end: number;
 18→  query: string;
 19→};
 20→
 21→type WorkspaceFile = {
 22→  path: string;
 23→  size?: number;
 24→};
 25→
 26→export type MentionOptionBase = {
 27→  id: string;
 28→  type: "attachment" | "workspace";
 29→  label: string;
 30→  description?: string;
 31→  insertValue: string;
 32→  meta?: {
 33→    path?: string;
 34→    size?: number;
 35→    mediaType?: string;
 36→  };
 37→};
 38→
 39→export type MentionOption = MentionOptionBase & {
 40→  order: number;
 41→};
 42→
 43→export type MentionSections = {
 44→  attachments: MentionOption[];
 45→  workspace: MentionOption[];
 46→};
 47→
 48→type UseFileMentionsArgs = {
 49→  text: string;
 50→  setText: (value: string) => void;
 51→  textareaRef: React.RefObject<HTMLTextAreaElement | null>;
 52→  attachments: (FileUIPart & { id: string })[];
 53→  sessionId?: string;
 54→  listDirectory?: (
 55→    sessionId: string,
 56→    path?: string,
 57→  ) => Promise<SessionFileEntry[]>;
 58→};
 59→
 60→type UseFileMentionsReturn = {
 61→  isOpen: boolean;
 62→  query: string;
 63→  flatOptions: MentionOption[];
 64→  sections: MentionSections;
 65→  activeIndex: number;
 66→  setActiveIndex: (value: number) => void;
 67→  handleTextChange: (value: string, caret: number | null) => void;
 68→  handleCaretChange: (caret: number | null) => void;
 69→  handleKeyDown: (event: KeyboardEvent<HTMLTextAreaElement>) => void;
 70→  selectOption: (option?: MentionOption) => void;
 71→  closeMenu: () => void;
 72→  workspaceStatus: "idle" | "loading" | "ready" | "error";
 73→  workspaceError: string | null;
 74→  retryWorkspace: () => void;
 75→  workspaceFileCount: number;
 76→};
 77→
 78→const detectMention = (
 79→  text: string,
 80→  caret: number | null,
 81→): MentionRange | null => {
 82→  const safeCaret = Math.max(0, Math.min(text.length, caret ?? text.length));
 83→  const upToCaret = text.slice(0, safeCaret);
 84→  const triggerIndex = upToCaret.lastIndexOf("@");
 85→  if (triggerIndex === -1) {
 86→    return null;
 87→  }
 88→
 89→  if (triggerIndex > 0) {
 90→    const previousChar = upToCaret[triggerIndex - 1];
 91→    if (previousChar && !MENTION_TRIGGER_PREFIX.test(previousChar)) {
 92→      return null;
 93→    }
 94→  }
 95→
 96→  const query = upToCaret.slice(triggerIndex + 1);
 97→  if (STOP_CHARS.test(query)) {
 98→    return null;
 99→  }
100→
101→  return {
102→    start: triggerIndex,
103→    end: safeCaret,
104→    query,
105→  };
106→};
107→
108→const isSameRange = (a: MentionRange | null, b: MentionRange | null): boolean =>
109→  a?.start === b?.start && a?.end === b?.end && a?.query === b?.query;
110→
111→const normalizePath = (value: string) => {
112→  if (value === "." || value === "./" || value === "") {
113→    return ".";
114→  }
115→  return value.replace(LEADING_DOT_SLASH, "");
116→};
117→
118→const crawlWorkspace = async ({
119→  sessionId,
120→  listDirectory,
121→}: {
122→  sessionId: string;
123→  listDirectory: UseFileMentionsArgs["listDirectory"];
124→}): Promise<WorkspaceFile[]> => {
125→  if (!listDirectory) {
126→    return [];
127→  }
128→
129→  const files: WorkspaceFile[] = [];
130→  const queue: string[] = ["."];
131→  const visited = new Set<string>();
132→
133→  while (
134→    queue.length > 0 &&
135→    files.length < MAX_WORKSPACE_FILES &&
136→    visited.size < MAX_DIRECTORY_SCANS
137→  ) {
138→    const current = queue.shift() as string;
139→    if (visited.has(current)) {
140→      continue;
141→    }
142→    visited.add(current);
143→
144→    // "." should be treated as undefined for API root
145→    const path = current === "." ? undefined : current;
146→    const entries = await listDirectory(sessionId, path);
147→
148→    for (const entry of entries) {
149→      const fullPath =
150→        current === "."
151→          ? entry.name
152→          : `${normalizePath(current)}/${entry.name}`;
153→      if (entry.type === "directory") {
154→        queue.push(fullPath);
155→        continue;
156→      }
157→      files.push({
158→        path: fullPath,
159→        size: entry.size,
160→      });
161→      if (files.length >= MAX_WORKSPACE_FILES) {
162→        break;
163→      }
164→    }
165→  }
166→
167→  return files;
168→};
169→
170→const toAttachmentOptions = (
171→  attachments: (FileUIPart & { id: string })[],
172→): MentionOptionBase[] =>
173→  attachments.map((attachment, index) => {
174→    const label =
175→      attachment.filename && attachment.filename.trim().length > 0
176→        ? attachment.filename
177→        : `Attachment ${index + 1}`;
178→    return {
179→      id: `upload-${attachment.id}`,
180→      type: "attachment" as const,
181→      label,
182→      description: attachment.mediaType ?? "Pending upload",
183→      insertValue: label,
184→      meta: {
185→        mediaType: attachment.mediaType,
186→      },
187→    };
188→  });
189→
190→const toWorkspaceOptions = (files: WorkspaceFile[]): MentionOptionBase[] =>
191→  files.map((file) => {
192→    const segments = file.path.split("/");
193→    const label = segments.at(-1) ?? file.path;
194→    return {
195→      id: `workspace-${file.path}`,
196→      type: "workspace" as const,
197→      label,
198→      description: file.path,
199→      insertValue: file.path,
200→      meta: {
201→        path: file.path,
202→        size: file.size,
203→      },
204→    };
205→  });
206→
207→const filterOptions = (
208→  options: MentionOptionBase[],
209→  query: string,
210→  offset: number,
211→): MentionOption[] => {
212→  if (!options.length) {
213→    return [];
214→  }
215→  const normalizedQuery = query.trim().toLowerCase();
216→  const matchesQuery = (value?: string) =>
217→    normalizedQuery.length === 0
218→      ? true
219→      : value?.toLowerCase().includes(normalizedQuery);
220→
221→  return options
222→    .filter(
223→      (option) =>
224→        matchesQuery(option.insertValue) ||
225→        matchesQuery(option.label) ||
226→        matchesQuery(option.description),
227→    )
228→    .map((option, index) => ({
229→      ...option,
230→      order: offset + index,
231→    }));
232→};
233→
234→export const useFileMentions = ({
235→  text,
236→  setText,
237→  textareaRef,
238→  attachments,
239→  sessionId,
240→  listDirectory,
241→}: UseFileMentionsArgs): UseFileMentionsReturn => {
242→  const [range, setRange] = useState<MentionRange | null>(null);
243→  const [activeIndex, setActiveIndex] = useState(0);
244→  const [workspaceFiles, setWorkspaceFiles] = useState<WorkspaceFile[]>([]);
245→  const [workspaceStatus, setWorkspaceStatus] = useState<
246→    "idle" | "loading" | "ready" | "error"
247→  >("idle");
248→  const [workspaceError, setWorkspaceError] = useState<string | null>(null);
249→  const workspaceRequestRef = useRef(0);
250→  const lastLoadedRef = useRef(0);
251→  const directoryQueryTimerRef = useRef<ReturnType<typeof setTimeout> | null>(
252→    null,
253→  );
254→  const [directoryFiles, setDirectoryFiles] = useState<WorkspaceFile[]>([]);
255→  const sessionIdRef = useRef(sessionId);
256→
257→  const attachmentOptions = useMemo(
258→    () => toAttachmentOptions(attachments),
259→    [attachments],
260→  );
261→  const mergedWorkspaceFiles = useMemo(() => {
262→    if (directoryFiles.length === 0) {
263→      return workspaceFiles;
264→    }
265→    const existing = new Set(workspaceFiles.map((f) => f.path));
266→    const extra = directoryFiles.filter((f) => !existing.has(f.path));
267→    return extra.length === 0 ? workspaceFiles : [...workspaceFiles, ...extra];
268→  }, [workspaceFiles, directoryFiles]);
269→
270→  const workspaceOptions = useMemo(
271→    () => toWorkspaceOptions(mergedWorkspaceFiles),
272→    [mergedWorkspaceFiles],
273→  );
274→
275→  const sections = useMemo(() => {
276→    const attachmentsSection = filterOptions(
277→      attachmentOptions,
278→      range?.query ?? "",
279→      0,
280→    );
281→    const workspaceSection = filterOptions(
282→      workspaceOptions,
283→      range?.query ?? "",
284→      attachmentsSection.length,
285→    );
286→    return {
287→      attachments: attachmentsSection,
288→      workspace: workspaceSection,
289→    };
290→  }, [attachmentOptions, workspaceOptions, range?.query]);
291→
292→  const flatOptions = useMemo(
293→    () => [...sections.attachments, ...sections.workspace],
294→    [sections.attachments, sections.workspace],
295→  );
296→
297→  useEffect(() => {
298→    if (activeIndex < flatOptions.length) {
299→      return;
300→    }
301→    setActiveIndex(flatOptions.length === 0 ? 0 : flatOptions.length - 1);
302→  }, [activeIndex, flatOptions.length]);
303→
304→  useEffect(() => {
305→    setActiveIndex(0);
306→  }, []);
307→
308→  useEffect(() => {
309→    setWorkspaceFiles([]);
310→    setDirectoryFiles([]);
311→    setWorkspaceStatus("idle");
312→    setWorkspaceError(null);
313→    workspaceRequestRef.current += 1;
314→    lastLoadedRef.current = 0;
315→    sessionIdRef.current = sessionId;
316→  }, [sessionId]);
317→
318→  const loadWorkspaceFiles = useCallback(async () => {
319→    if (!(sessionId && listDirectory)) {
320→      return;
321→    }
322→    setWorkspaceStatus("loading");
323→    setWorkspaceError(null);
324→    workspaceRequestRef.current += 1;
325→    const requestId = workspaceRequestRef.current;
326→    try {
327→      const files = await crawlWorkspace({ sessionId, listDirectory });
328→      if (workspaceRequestRef.current !== requestId) {
329→        return;
330→      }
331→      setWorkspaceFiles(files);
332→      setWorkspaceStatus("ready");
333→      lastLoadedRef.current = Date.now();
334→    } catch (error) {
335→      if (workspaceRequestRef.current !== requestId) {
336→        return;
337→      }
338→      setWorkspaceStatus("error");
339→      setWorkspaceError(
340→        error instanceof Error
341→          ? error.message
342→          : "Failed to load workspace files",
343→      );
344→    }
345→  }, [sessionId, listDirectory]);
346→
347→  useEffect(() => {
348→    if (!range) {
349→      return;
350→    }
351→    if (!(sessionId && listDirectory)) {
352→      return;
353→    }
354→    if (workspaceStatus === "loading") {
355→      return;
356→    }
357→    const isStale =
358→      workspaceStatus === "ready" &&
359→      Date.now() - lastLoadedRef.current > WORKSPACE_STALE_MS;
360→    if (workspaceStatus !== "idle" && !isStale) {
361→      return;
362→    }
363→    loadWorkspaceFiles();
364→  }, [range, sessionId, listDirectory, workspaceStatus, loadWorkspaceFiles]);
365→
366→  // Debounced directory query when query contains "/"
367→  useEffect(() => {
368→    if (directoryQueryTimerRef.current) {
369→      clearTimeout(directoryQueryTimerRef.current);
370→      directoryQueryTimerRef.current = null;
371→    }
372→    const query = range?.query ?? "";
373→    const slashIndex = query.lastIndexOf("/");
374→    if (slashIndex < 0 || !(sessionId && listDirectory)) {
375→      setDirectoryFiles([]);
376→      return;
377→    }
378→    const dirPrefix = query.slice(0, slashIndex);
379→    const dirPath = dirPrefix === "" ? undefined : dirPrefix;
380→    const capturedSessionId = sessionId;
381→    directoryQueryTimerRef.current = setTimeout(async () => {
382→      if (sessionIdRef.current !== capturedSessionId) return;
383→      try {
384→        const entries = await listDirectory(capturedSessionId, dirPath);
385→        const files: WorkspaceFile[] = [];
386→        for (const entry of entries) {
387→          if (entry.type === "directory") {
388→            continue;
389→          }
390→          const fullPath = dirPath
391→            ? `${dirPath}/${entry.name}`
392→            : entry.name;
393→          files.push({ path: fullPath, size: entry.size });
394→        }
395→        setDirectoryFiles(files);
396→      } catch {
397→        // Silently ignore — the main index is still available
398→      }
399→    }, DIRECTORY_QUERY_DEBOUNCE_MS);
400→    return () => {
401→      if (directoryQueryTimerRef.current) {
402→        clearTimeout(directoryQueryTimerRef.current);
403→        directoryQueryTimerRef.current = null;
404→      }
405→    };
406→  }, [range?.query, sessionId, listDirectory]);
407→
408→  useEffect(() => {
409→    const caret = textareaRef.current?.selectionStart ?? text.length;
410→    const next = detectMention(text, caret);
411→    setRange((previous) => (isSameRange(previous, next) ? previous : next));
412→  }, [text, textareaRef]);
413→
414→  const handleTextChange = useCallback(
415→    (value: string, caret: number | null) => {
416→      setRange(detectMention(value, caret));
417→    },
418→    [],
419→  );
420→
421→  const handleCaretChange = useCallback(
422→    (caret: number | null) => {
423→      setRange(detectMention(text, caret));
424→    },
425→    [text],
426→  );
427→
428→  const closeMenu = useCallback(() => {
429→    setRange(null);
430→  }, []);
431→
432→  const selectOption = useCallback(
433→    (option?: MentionOption) => {
434→      if (!range) {
435→        return;
436→      }
437→      const target = option ?? flatOptions[activeIndex];
438→      if (!target) {
439→        return;
440→      }
441→
442→      const mentionText = `@${target.insertValue}`;
443→      const before = text.slice(0, range.start);
444→      const after = text.slice(range.end);
445→      const needsSpace =
446→        after.length === 0 || NON_WHITESPACE_START.test(after) ? " " : "";
447→      const nextValue = `${before}${mentionText}${needsSpace}${after}`;
448→      const nextCaret = before.length + mentionText.length + needsSpace.length;
449→
450→      setText(nextValue);
451→      setRange(null);
452→      setActiveIndex(0);
453→
454→      requestAnimationFrame(() => {
455→        const node = textareaRef.current;
456→        if (!node) {
457→          return;
458→        }
459→        node.focus();
460→        node.setSelectionRange(nextCaret, nextCaret);
461→      });
462→    },
463→    [range, flatOptions, activeIndex, text, setText, textareaRef],
464→  );
465→
466→  const handleKeyDown = useCallback(
467→    (event: KeyboardEvent<HTMLTextAreaElement>) => {
468→      if (!range) {
469→        return;
470→      }
471→
472→      if (event.key === "ArrowDown") {
473→        if (flatOptions.length === 0) {
474→          return;
475→        }
476→        event.preventDefault();
477→        setActiveIndex((previous) => (previous + 1) % flatOptions.length);
478→        return;
479→      }
480→
481→      if (event.key === "ArrowUp") {
482→        if (flatOptions.length === 0) {
483→          return;
484→        }
485→        event.preventDefault();
486→        setActiveIndex((previous) =>
487→          previous - 1 < 0
488→            ? flatOptions.length - 1
489→            : (previous - 1) % flatOptions.length,
490→        );
491→        return;
492→      }
493→
494→      if (event.key === "Enter" || event.key === "Tab") {
495→        if (flatOptions.length === 0) {
496→          return;
497→        }
498→        event.preventDefault();
499→        selectOption();
500→        return;
501→      }
502→
503→      if (event.key === "Escape") {
504→        event.preventDefault();
505→        closeMenu();
506→      }
507→    },
508→    [range, flatOptions, selectOption, closeMenu],
509→  );
510→
511→  const retryWorkspace = useCallback(() => {
512→    loadWorkspaceFiles();
513→  }, [loadWorkspaceFiles]);
514→
515→  return {
516→    isOpen: Boolean(range),
517→    query: range?.query ?? "",
518→    flatOptions,
519→    sections,
520→    activeIndex,
521→    setActiveIndex,
522→    handleTextChange,
523→    handleCaretChange,
524→    handleKeyDown,
525→    selectOption,
526→    closeMenu,
527→    workspaceStatus,
528→    workspaceError,
529→    retryWorkspace,
530→    workspaceFileCount: workspaceFiles.length,
531→  };
532→};
