 11→const formatFileSize = (size?: number): string | null => {
 12→  if (size === null || size === undefined) {
 13→    return null;
 14→  }
 15→  if (size === 0) {
 16→    return "0 B";
 17→  }
 18→  const units = ["B", "KB", "MB", "GB", "TB"];
 19→  let value = size;
 20→  let idx = 0;
 21→  while (value >= 1024 && idx < units.length - 1) {
 22→    value /= 1024;
 23→    idx += 1;
 24→  }
 25→  const precision = value >= 10 ? 0 : 1;
 26→  return `${value.toFixed(precision)} ${units[idx]}`;
 27→};
